em.forEach(e=>{const pr=getPR(e.pd);for(let dt=new Date(pr.ed);dt>=pr.sd;dt.setDate(dt.getDate()-1)){const chk=new Date(dt);chk.setHours(0,0,0,0);if(chk>today3)continue;const ds=chk.getFullYear()+"-"+String(chk.getMonth()+1).padStart(2,"0")+"-"+String(chk.getDate()).padStart(2,"0");allDates.add(ds);}});
